/**
 * fix-kategori.php
 * Deploy: Dropdown Kategori Mesyuarat (5 item baharu, tiada Lain-lain)
 * Run: https://ibookbptm.great-site.net/fix-kategori.php?key=ibook2026deploy
 */
if (($_GET['key'] ?? '') !== 'ibook2026deploy') { http_response_code(403); exit('Forbidden'); }

$root = __DIR__;

function deployFile($root, $rel, $b64) {
    $target = $root . '/' . $rel;
    $dir    = dirname($target);
    if (!is_dir($dir)) mkdir($dir, 0755, true);
    $bytes = base64_decode($b64);
    if (file_put_contents($target, $bytes) === false) { echo "ERR write: $rel\n"; return; }
    echo "OK  $rel (" . strlen($bytes) . " bytes)\n";
}

function clearBladeCache($root) {
    $dir = $root . '/storage/framework/views';
    if (!is_dir($dir)) { echo "SKIP blade cache\n"; return; }
    $n = 0;
    foreach (glob($dir . '/*.php') as $f) { @unlink($f); $n++; }
    echo "OK  blade cache dibersihkan ($n fail)\n";
}

header('Content-Type: text/plain; charset=utf-8');
