    'app/Http/Controllers/TempahanController.php' => '',
    'app/Http/Controllers/TempahanBerulangController.php' => '',
    'resources/views/tempahan/create.blade.php' => '',
    'resources/views/tempahan/edit.blade.php' => '',
    'resources/views/kalendar/index.blade.php' => '',
];
foreach ($files as $rel => $b64) {
    deployFile($root, $rel, $b64);
